/** Correct player name shown for scoring (must match the image asset for that question). */
export function getGuessPhotoCorrectPlayerName(q: Question): string {
  const opts = { A: q.optionA, B: q.optionB, C: q.optionC, D: q.optionD };
  return opts[q.correctAnswer];
}

if (import.meta.env.DEV) {
  const seenImage = new Map<string, string>();
  for (const q of guessWhoPhotoQuestions) {
    const correct = getGuessPhotoCorrectPlayerName(q);
    if (!correct.trim()) {
      throw new Error(`[guess-who-photo] ${q.id}: correctAnswer has no label`);
    }
    const img = q.image ?? '';
    if (seenImage.has(img) && seenImage.get(img) !== q.id) {
      throw new Error(
        `[guess-who-photo] Duplicate image for ${seenImage.get(img)} and ${q.id} — wrong player photo pairing`
      );
    }
    seenImage.set(img, q.id);
  }
}

export const guessWhoPhotoQuestionsByCountry = {
  nigeria: guessWhoPhotoQuestions.filter((q) => q.country === 'nigeria'),
  mexico: guessWhoPhotoQuestions.filter((q) => q.country === 'mexico'),
  colombia: guessWhoPhotoQuestions.filter((q) => q.country === 'colombia'),
  japan: guessWhoPhotoQuestions.filter((q) => q.country === 'japan'),
  uruguay: guessWhoPhotoQuestions.filter((q) => q.country === 'uruguay'),
} as const;

/** Questions per round; level count follows from total photos in the pool. */
export const GUESS_PHOTO_QUESTIONS_PER_LEVEL = 10;

export const GUESS_PHOTO_LEVEL_COUNT = Math.ceil(
  guessWhoPhotoQuestions.length / GUESS_PHOTO_QUESTIONS_PER_LEVEL
);

/**
 * "Vintage" / old-school faces (pre-2000s icons or classic film-era portraits) — placed in the last levels.
 * Remaining pool is split: first chunk ≈ modern/recognisable faces, middle = classic 90s–2000s.
 */
const GUESS_PHOTO_VINTAGE_IDS = new Set<string>([
  'gwp-2',
  'gwp-11',
  'gwp-12',
  'gwp-13',
  'gwp-14',
  'gwp-19',
  'gwp-32',
  'gwp-34',
  'gwp-42',
  'gwp-43',
  'gwp-44',
  'gwp-45',
  'gwp-50',
  'gwp-51',
  'gwp-52',
  'gwp-53',
  'gwp-58',
  'gwp-82',
  'gwp-83',
  'gwp-100',
  'gwp-106',
  'gwp-113',
  'gwp-115',
  'gwp-128',
  'gwp-147',
]);

/** First N non-vintage questions (sorted by id) = easier rounds — recent stars & clear kit photos. */
const GUESS_PHOTO_MODERN_POOL_SIZE = 80;

function compareGuessPhotoQuestionId(a: string, b: string): number {
  const rank = (id: string): number => {
    if (id === 'gwp-1b') return 1.5;
    const m = id.match(/^gwp-(\d+)/);
    return m ? parseInt(m[1], 10) : 0;
  };
  return rank(a) - rank(b);
}

function buildGuessPhotoQuestionsOrder(): Question[] {
  const vintage: Question[] = [];
  const nonVintage: Question[] = [];
  for (const q of guessWhoPhotoQuestions) {
    if (GUESS_PHOTO_VINTAGE_IDS.has(q.id)) vintage.push(q);
    else nonVintage.push(q);
  }
  nonVintage.sort((a, b) => compareGuessPhotoQuestionId(a.id, b.id));
  vintage.sort((a, b) => compareGuessPhotoQuestionId(a.id, b.id));
  const modern = nonVintage.slice(0, GUESS_PHOTO_MODERN_POOL_SIZE);
  const classic = nonVintage.slice(GUESS_PHOTO_MODERN_POOL_SIZE);
  return [...modern, ...classic, ...vintage];
}

const ORDERED_GUESS_PHOTO_QUESTIONS = buildGuessPhotoQuestionsOrder();

/** Level L uses a fixed slice of the era-ordered pool (same level = same questions every time). */
export function getGuessWhoPhotoQuestionsByLevel(level: number): Question[] {
  const start = (level - 1) * GUESS_PHOTO_QUESTIONS_PER_LEVEL;
  return ORDERED_GUESS_PHOTO_QUESTIONS.slice(start, start + GUESS_PHOTO_QUESTIONS_PER_LEVEL);
}
